#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

// Minimum time to go distance K with max speed limit X at finish
ll min_time(ll K, ll X) {
    // Binary search on total time t
    ll lo = 1, hi = 2e9; // upper bound large enough
    while (lo < hi) {
        ll t = (lo + hi) / 2;
        // Max distance we can cover in time t with speed limit X at finish

        // We can think of the speed profile:
        // Accelerate for some time, maybe cruise, then decelerate to <= X at finish.
        // The maximum distance we can cover in time t while ending at speed <= X
        // is: we can accelerate to some peak speed V, then decelerate to at most X.
        // The speed changes by at most 1 per second.
        // The total distance = sum of speeds over t seconds.

        // Another approach: The minimal time to cover K with final speed <= X.
        // We can binary search and check if distance achievable in t seconds >= K.

        // Maximum distance possible in t seconds with final speed <= X:
        // Let's compute maximum possible distance.
        // We can accelerate for a seconds, then cruise (optional), then decelerate for d seconds.
        // a + d <= t, and final speed = a - d <= X (since start 0, accelerate to a, decelerate by d).
        // Actually start 0, accelerate for a seconds -> speed = a.
        // Then we might maintain speed for some time, but for max distance at given t and final speed <= X,
        // we want as high speed as possible early.
        // The optimal: accelerate as fast as possible to some peak, then decelerate to <= X at the end.
        // Let peak = v. Then we need a seconds to reach v, d seconds to go from v down to <= X.
        // a = v, d = max(0, v - X). So a + d = v + max(0, v - X) = max(v, 2v - X).
        // Time spent at peak speed = t - a - d (if positive).
        // Distance = sum_{i=1}^{a} i + (t - a - d) * v + sum_{j=1}^{d} (v - j)
        // = a(a+1)/2 + (t - a - d) * v + d*v - d(d+1)/2
        // = a(a+1)/2 + (t - a - d) * v + d*v - d(d+1)/2

        // But we can just simulate greedily? Let's derive a simpler formula.

        // Actually the classic "race" problem (USACO "race").
        // The known solution: binary search on time.
        // For a given time t, the maximum possible speed at finish limited to X,
        // the max distance we can cover:

        // Let's think differently. We want to know if we can reach distance >= K in time t
        // with final speed <= X.

        // Maximum distance in t seconds:
        // If t <= X: we can accelerate for t seconds, reach speed t, distance = t(t+1)/2. Final speed = t <= X.
        // If t > X: We can accelerate to some peak speed V, then decelerate to X at finish.
        // Time to reach peak V from 0: V seconds.
        // Time to decelerate from V to X: V - X seconds.
        // So V + (V - X) = 2V - X seconds spent on acceleration/deceleration.
        // Remaining time t - (2V - X) can be spent at speed V.
        // To maximize distance given t, we want V as large as possible, but must have 2V - X <= t, i.e., V <= (t + X) / 2.
        // So max peak V = (t + X) / 2 (integer division).
        // Let V = (t + X) / 2.
        // Then a = V (accel time), d = V - X (decel time). Time at peak = t - V - (V - X) = t - 2V + X.
        // Distance = sum_{i=1}^{V} i + (t - 2V + X) * V + sum_{j=1}^{V-X} (V - j)
        // = V(V+1)/2 + (t - 2V + X) * V + (V-X)*V - (V-X)(V-X+1)/2

        ll maxDist;
        if (t <= X) {
            maxDist = t * (t + 1) / 2;
        } else {
            ll V = (t + X) / 2;
            ll a = V;
            ll d = V - X;
            ll peak_time = t - a - d; // time at speed V
            // distance during acceleration: 1+2+...+V = V*(V+1)/2
            ll acc_dist = V * (V + 1) / 2;
            // distance during deceleration: V + (V-1) + ... + (X+1) = sum_{j=1}^{V-X} (V - j)
            // = (V-1) + (V-2) + ... + X = sum from X+1 to V-1 = (V-1+X+1)*(V-1-X)/2 = (V+X)*(V-X-1)/2... let's compute directly:
            // deceleration starts at speed V, ends at speed X, goes down by 1 each second.
            // distances: V, V-1, ..., X+1. Number of terms = V - X.
            // Sum = (V + (X+1)) * (V-X) / 2 = (V+X+1)*(V-X)/2
            ll dec_dist = (V + X + 1) * (V - X) / 2;
            // distance at peak
            ll peak_dist = peak_time * V;
            maxDist = acc_dist + peak_dist + dec_dist;
        }

        if (maxDist >= K) {
            hi = t;
        } else {
            lo = t + 1;
        }
    }
    return lo;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll K;
    int N;
    cin >> K >> N;
    while (N--) {
        ll X;
        cin >> X;
        cout << min_time(K, X) << "\n";
    }

    return 0;
}
